"""
function suggest end

function suggest(QueryText; aws_config::AbstractAWSConfig=current_aws_config())
    return geo_places(
        "POST",
        "/v2/suggest",
        Dict{String,Any}("QueryText" => QueryText);
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

function suggest(
    QueryText,
    params::AbstractDict{String};
    aws_config::AbstractAWSConfig=current_aws_config(),
)
    return geo_places(
        "POST",
        "/v2/suggest",
        Dict{String,Any}(
            mergewith(_merge, Dict{String,Any}("QueryText" => QueryText), params)
        );
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end
